            int v = arr[2 + 2 * i + 1];
            adj[u].Add(v);
            inDegree[v]++;
        }

        Queue<int> queue = new Queue<int>();
        for (int v = 0; v < numVertices; v++)
        {
            if (inDegree[v] == 0)
            {
                queue.Enqueue(v);
            }
