fun topologicalSortKahn(arr: IntArray): IntArray {
    if (arr.size < 2) {
        return intArrayOf()
    }

    val numVertices = arr[0]
    val numEdges = arr[1]

    val adj = Array(numVertices) { mutableListOf<Int>() }
    val inDegree = IntArray(numVertices)

    for (i in 0 until numEdges) {
        val u = arr[2 + 2 * i]
        val v = arr[2 + 2 * i + 1]
        adj[u].add(v)
        inDegree[v]++
    }

    val queue = LinkedList<Int>()
    for (v in 0 until numVertices) {
        if (inDegree[v] == 0) {
            queue.add(v)
        }
    }

    val result = mutableListOf<Int>()
    while (queue.isNotEmpty()) {
        val u = queue.poll()
        result.add(u)
        for (v in adj[u]) {
            inDegree[v]--
            if (inDegree[v] == 0) {
                queue.add(v)
            }
        }
    }

    return if (result.size == numVertices) {
        result.toIntArray()
    } else {
        intArrayOf()
    }
}

from collections import deque


def topological_sort_kahn(arr: list[int]) -> list[int]:
    if len(arr) < 2:
        return []

    num_vertices = arr[0]
    num_edges = arr[1]

    adj: list[list[int]] = [[] for _ in range(num_vertices)]
    in_degree = [0] * num_vertices

    for i in range(num_edges):
        u = arr[2 + 2 * i]
        v = arr[2 + 2 * i + 1]
        adj[u].append(v)
        in_degree[v] += 1

    queue = deque()
    for v in range(num_vertices):
        if in_degree[v] == 0:
            queue.append(v)

    result: list[int] = []
    while queue:
        u = queue.popleft()
        result.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if len(result) == num_vertices:
        return result
    return []

use std::collections::VecDeque;

pub fn topological_sort_kahn(arr: &[i32]) -> Vec<i32> {
    if arr.len() < 2 {
        return vec![];
    }

    let num_vertices = arr[0] as usize;
    let num_edges = arr[1] as usize;

    let mut adj: Vec<Vec<usize>> = vec![vec![]; num_vertices];
    let mut in_degree = vec![0usize; num_vertices];

    for i in 0..num_edges {
        let u = arr[2 + 2 * i] as usize;
        let v = arr[2 + 2 * i + 1] as usize;
        adj[u].push(v);
        in_degree[v] += 1;
    }

    let mut queue = VecDeque::new();
    for v in 0..num_vertices {
        if in_degree[v] == 0 {
            queue.push_back(v);
        }
    }

    let mut result = Vec::new();
    while let Some(u) = queue.pop_front() {
        result.push(u as i32);
        for &v in &adj[u] {
            in_degree[v] -= 1;
            if in_degree[v] == 0 {
                queue.push_back(v);
            }
        }
    }

    if result.len() == num_vertices {
        result
    } else {
        vec![]
    }
}

import scala.collection.mutable

object TopologicalSortKahn {

  def topologicalSortKahn(arr: Array[Int]): Array[Int] = {
    if (arr.length < 2) return Array.empty[Int]

    val numVertices = arr(0)
    val numEdges = arr(1)

    val adj = Array.fill(numVertices)(mutable.ListBuffer[Int]())
    val inDegree = Array.fill(numVertices)(0)

    for (i <- 0 until numEdges) {
      val u = arr(2 + 2 * i)
      val v = arr(2 + 2 * i + 1)
      adj(u) += v
      inDegree(v) += 1
    }

    val queue = mutable.Queue[Int]()
    for (v <- 0 until numVertices) {
      if (inDegree(v) == 0) {
        queue.enqueue(v)
      }
    }

    val result = mutable.ListBuffer[Int]()
    while (queue.nonEmpty) {
      val u = queue.dequeue()
      result += u
      for (v <- adj(u)) {
        inDegree(v) -= 1
        if (inDegree(v) == 0) {
          queue.enqueue(v)
        }
      }
    }

    if (result.size == numVertices) result.toArray
    else Array.empty[Int]
  }
}

func topologicalSortKahn(_ arr: [Int]) -> [Int] {
    if arr.count < 2 {
        return []
    }

    let numVertices = arr[0]
    let numEdges = arr[1]

    var adj = [[Int]](repeating: [], count: numVertices)
    var inDegree = [Int](repeating: 0, count: numVertices)

    for i in 0..<numEdges {
        let u = arr[2 + 2 * i]
        let v = arr[2 + 2 * i + 1]
        adj[u].append(v)
        inDegree[v] += 1
    }

    var queue: [Int] = []
    for v in 0..<numVertices {
        if inDegree[v] == 0 {
            queue.append(v)
        }
    }

    var result: [Int] = []
    var front = 0
    while front < queue.count {
        let u = queue[front]
        front += 1
        result.append(u)
        for v in adj[u] {
            inDegree[v] -= 1
            if inDegree[v] == 0 {
                queue.append(v)
            }
        }
    }

    if result.count == numVertices {
        return result
    }
    return []
}

export function topologicalSortKahn(arr: number[]): number[] {
    if (arr.length < 2) {
        return [];
    }

    const numVertices = arr[0];
    const numEdges = arr[1];

    const adj: number[][] = Array.from({ length: numVertices }, () => []);
    const inDegree = new Array(numVertices).fill(0);

    for (let i = 0; i < numEdges; i++) {
        const u = arr[2 + 2 * i];
        const v = arr[2 + 2 * i + 1];
        adj[u].push(v);
        inDegree[v]++;
    }

    const queue: number[] = [];
    for (let v = 0; v < numVertices; v++) {
        if (inDegree[v] === 0) {
            queue.push(v);
        }
    }

    const result: number[] = [];
    let front = 0;
    while (front < queue.length) {
        const u = queue[front++];
        result.push(u);
        for (const v of adj[u]) {
            inDegree[v]--;
            if (inDegree[v] === 0) {
                queue.push(v);
            }
        }
    }

    if (result.length === numVertices) {
        return result;
    }
    return [];
}
